import { getAgentByWorkspaceAndName } from "../../db/agents.js";
import { getCustomerById } from "../../db/customers.js";
import { resolveRoleConfig } from "../role-config.js";
import { resolveModelForRole } from "../model-tiers.js";
import { workspaceSlugFromCustomer } from "../slug.js";
import type { StepContext, StepResult } from "./types.js";

export async function step2ValidateInputs(ctx: StepContext): Promise<StepResult> {
  const customer = (ctx.state.customer as Awaited<ReturnType<typeof getCustomerById>> | undefined) ??
    (await getCustomerById(ctx.db, ctx.input.customerId));

  if (!customer) {
    return {
      ok: false,
      errorCode: "CUSTOMER_NOT_FOUND",
      errorMessage: "Customer not found"
    };
  }

  const workspaceSlug = workspaceSlugFromCustomer(customer.customer_id, customer.workspace_slug);
  const existingAgent = await getAgentByWorkspaceAndName(ctx.db, workspaceSlug, ctx.input.agentName);
  if (existingAgent) {
    return {
      ok: false,
      errorCode: "AGENT_NAME_CONFLICT",
      errorMessage: "Agent name already exists in workspace"
    };
  }

  const tierSpec = resolveModelForRole(ctx.input.role, ctx.input.modelTier);
  const roleConfig = resolveRoleConfig(ctx.input.role);

  return {
    ok: true,
    data: {
      customer,
      workspaceSlug,
      tierSpec,
      roleConfig
    }
  };
}

export async function rollbackStep2ValidateInputs(ctx: StepContext): Promise<void> {
  ctx.logger.info("rolling back step_2_validate_inputs: no external state to rollback");
}

import { copyFileSync, existsSync, readdirSync } from "node:fs";
import { mkdir } from "node:fs/promises";
import os from "node:os";
import path from "node:path";
import { CEO_ROLES } from "../model-tiers.js";
import { openclawAgentIdFor, workspacePathFor } from "../slug.js";
import type { StepContext, StepResult } from "./types.js";

const expandHome = (value: string): string => {
  if (value === "~") {
    return os.homedir();
  }
  if (value.startsWith("~/")) {
    return path.join(os.homedir(), value.slice(2));
  }
  return value;
};

const resolveTemplateDir = (workspaceTemplate: string): string => {
  const direct = path.resolve(process.cwd(), workspaceTemplate);
  if (existsSync(direct)) {
    return direct;
  }
  const parent = path.resolve(process.cwd(), "..", workspaceTemplate);
  return parent;
};

export async function step3CreateWorkspace(ctx: StepContext): Promise<StepResult> {
  const workspaceSlug = ctx.state.workspaceSlug as string | undefined;
  if (!workspaceSlug) {
    return {
      ok: false,
      errorCode: "WORKSPACE_SLUG_MISSING",
      errorMessage: "workspace slug missing from state"
    };
  }

  const openclawAgentId = openclawAgentIdFor(workspaceSlug, ctx.input.agentName);
  const workspacePath = ctx.input.workspacePath ?? workspacePathFor(openclawAgentId);
  const resolvedWorkspacePath = expandHome(workspacePath);

  await mkdir(resolvedWorkspacePath, { recursive: true });
  const roleSpecificTemplate = `config/${ctx.input.role.replace(/_/g, "-")}-workspace`;
  const workspaceTemplate = CEO_ROLES.has(ctx.input.role)
    ? "config/ceo-workspace"
    : existsSync(resolveTemplateDir(roleSpecificTemplate))
      ? roleSpecificTemplate
      : "config/worker-workspace";
  const templateDir = resolveTemplateDir(workspaceTemplate);
  const filesToCopy = CEO_ROLES.has(ctx.input.role)
    ? ["SOUL.md", "HEARTBEAT.md", "AGENTS.md", "USER.md", "IDENTITY.md"]
    : readdirSync(templateDir).filter((file) => file.endsWith(".md"));

  for (const file of filesToCopy) {
    const src = path.resolve(templateDir, file);
    const dest = path.resolve(resolvedWorkspacePath, file);
    if (existsSync(src)) {
      copyFileSync(src, dest);
    }
  }

  return {
    ok: true,
    data: {
      openclawAgentId,
      workspacePath: resolvedWorkspacePath
    }
  };
}

export async function rollbackStep3CreateWorkspace(ctx: StepContext): Promise<void> {
  const workspacePath = ctx.state.workspacePath as string | undefined;
  ctx.logger.info(
    { workspacePath: workspacePath ?? null },
    "rolling back step_3_create_workspace: cleanup deferred to maintenance task"
  );
}

import type { StepContext, StepResult } from "./types.js";
import { OpenClawAgentExistsError } from "../../clients/openclaw/errors.js";

export async function step4OpenClawAdd(ctx: StepContext): Promise<StepResult> {
  const openclawAgentId = ctx.state.openclawAgentId as string | undefined;
  const workspacePath = ctx.state.workspacePath as string | undefined;

  if (!openclawAgentId || !workspacePath) {
    return {
      ok: false,
      errorCode: "OPENCLAW_INPUT_MISSING",
      errorMessage: "openclaw agent id or workspace path missing"
    };
  }

  let openclawAgent;
  try {
    openclawAgent = await ctx.clients.openclaw.addAgent({
      id: openclawAgentId,
      workspace: workspacePath,
      identity: {
        name: ctx.input.agentName
      }
    });
  } catch (error) {
    if (!(error instanceof OpenClawAgentExistsError)) {
      throw error;
    }

    const existing = await ctx.clients.openclaw.getAgent(openclawAgentId);
    if (!existing) {
      throw error;
    }
    openclawAgent = existing;
  }

  return {
    ok: true,
    data: {
      openclawAgent
    }
  };
}

export async function rollbackStep4OpenClawAdd(ctx: StepContext): Promise<void> {
  const openclawAgentId = ctx.state.openclawAgentId as string | undefined;
  if (!openclawAgentId) {
    ctx.logger.info("rolling back step_4_openclaw_add: no agent id recorded");
    return;
  }
  ctx.logger.info({ openclawAgentId }, "rolling back step_4_openclaw_add: deleting openclaw agent");
  await ctx.clients.openclaw.deleteAgent(openclawAgentId);
}

import { env } from "../../config/env.js";
import type { Customer } from "../../db/customers.js";
import type { StepContext, StepResult } from "./types.js";

export async function step5PaperclipHire(ctx: StepContext): Promise<StepResult> {
  const customer = ctx.state.customer as Customer | undefined;
  const roleConfig = ctx.state.roleConfig as { paperclipRole: string; budgetMonthlyCents: number; capabilities: string } | undefined;

  if (!customer || !roleConfig) {
    return {
      ok: false,
      errorCode: "PAPERCLIP_INPUT_MISSING",
      errorMessage: "customer or role configuration missing"
    };
  }

  if (!customer.paperclip_company_id) {
    return {
      ok: false,
      errorCode: "PAPERCLIP_COMPANY_ID_MISSING",
      errorMessage: "customer.paperclip_company_id is required for hire flow"
    };
  }

  const isWorkerRole = ctx.input.role !== "ceo";
  const openclawAgentId = ctx.state.openclawAgentId as string | undefined;
  if (isWorkerRole && !openclawAgentId) {
    return {
      ok: false,
      errorCode: "OPENCLAW_AGENT_ID_MISSING",
      errorMessage: "openclaw agent id missing for worker process adapter"
    };
  }
  const adapterTimeoutSec = isWorkerRole ? 300 : 1500;
  const heartbeatConfig = isWorkerRole
    ? { enabled: true, mode: "reactive" as const }
    : { enabled: true, mode: "proactive" as const, intervalSec: 1800 };
  const workerProcessConfig = isWorkerRole
    ? {
        command: "/Users/jonathanborgia/foreman-git/foreman-v2/scripts/paperclip-openclaw-executor.sh",
        cwd: "/Users/jonathanborgia/foreman-git/foreman-v2",
        timeoutSec: adapterTimeoutSec,
        env: {
          FOREMAN_OPENCLAW_AGENT_ID: openclawAgentId!
        }
      }
    : null;
  const openclawGatewayConfig = {
    url: env.OPENCLAW_GATEWAY_URL,
    gatewayUrl: env.OPENCLAW_GATEWAY_URL,
    timeoutSec: adapterTimeoutSec,
    headers: {
      "x-openclaw-token": "pending-sync"
    }
  };

  const hireResponse = await ctx.clients.paperclip.hireAgent(customer.paperclip_company_id, {
    name: ctx.input.agentName,
    role: roleConfig.paperclipRole,
    capabilities: roleConfig.capabilities,
    budgetMonthlyCents: roleConfig.budgetMonthlyCents,
    adapterType: isWorkerRole ? "process" : "openclaw_gateway",
    adapterConfig: isWorkerRole ? workerProcessConfig! : openclawGatewayConfig,
    runtimeConfig: {
      heartbeat: heartbeatConfig
    }
  });

  const patchedAgent = await ctx.clients.paperclip.patchAgent(hireResponse.agent.id, {
    ...(isWorkerRole ? { adapterType: "process" } : {}),
    adapterConfig: {
      ...hireResponse.agent.adapterConfig,
      ...(isWorkerRole ? workerProcessConfig! : openclawGatewayConfig),
      timeoutSec: adapterTimeoutSec
    },
    runtimeConfig: {
      heartbeat: heartbeatConfig
    }
  });

  return {
    ok: true,
    data: {
      paperclipAgent: patchedAgent,
      pendingApproval: hireResponse.approval ?? null
    }
  };
}

export async function rollbackStep5PaperclipHire(ctx: StepContext): Promise<void> {
  const paperclipAgent = ctx.state.paperclipAgent as { id: string } | undefined;
  if (!paperclipAgent?.id) {
    ctx.logger.info("rolling back step_5_paperclip_hire: no paperclip agent id recorded");
    return;
  }
  ctx.logger.info(
    { paperclipAgentId: paperclipAgent.id },
    "rolling back step_5_paperclip_hire: deleting paperclip agent"
  );
  await ctx.clients.paperclip.deleteAgent(paperclipAgent.id);
}

import type { Customer } from "../../db/customers.js";
import type { PendingApproval } from "../../clients/paperclip/types.js";
import type { StepContext, StepResult } from "./types.js";
import process from "node:process";

export async function step6PaperclipApprove(ctx: StepContext): Promise<StepResult> {
  if (process.env.FOREMAN_FORCE_STEP6_FAILURE === "1") {
    return {
      ok: false,
      errorCode: "STEP6_FORCED_FAILURE",
      errorMessage: "step 6 forced failure for rollback smoke test"
    };
  }

  const customer = ctx.state.customer as Customer | undefined;
  if (!customer?.paperclip_company_id) {
    return {
      ok: false,
      errorCode: "PAPERCLIP_COMPANY_ID_MISSING",
      errorMessage: "paperclip company id is required for approvals"
    };
  }

  const existingApproval = ctx.state.pendingApproval as PendingApproval | null | undefined;
  let approval = existingApproval;

  if (!approval) {
    const pending = await ctx.clients.paperclip.listPendingApprovals(customer.paperclip_company_id);
    approval = pending.find((item) => item.type === "hire_agent" && item.status === "pending") ?? null;
  }

  if (!approval) {
    return {
      ok: false,
      errorCode: "PAPERCLIP_APPROVAL_NOT_FOUND",
      errorMessage: "No pending hire_agent approval found"
    };
  }

  await ctx.clients.paperclip.actOnApproval(approval.id, "approve");

  return {
    ok: true,
    data: {
      approvedId: approval.id
    }
  };
}

export async function rollbackStep6PaperclipApprove(ctx: StepContext): Promise<void> {
  ctx.logger.info("rolling back step_6_paperclip_approve: approval action is not undoable");
}

import type { PaperclipAgent } from "../../clients/paperclip/types.js";
import { safePatchAgent } from "../../clients/paperclip/safe-patch.js";
import type { StepContext, StepResult } from "./types.js";

export async function step7TokenSync(ctx: StepContext): Promise<StepResult> {
  const paperclipAgent = ctx.state.paperclipAgent as PaperclipAgent | undefined;
  if (!paperclipAgent) {
    return {
      ok: false,
      errorCode: "PAPERCLIP_AGENT_MISSING",
      errorMessage: "paperclip agent missing in state"
    };
  }

  const token = await ctx.clients.openclaw.readGatewayToken();
  await safePatchAgent(ctx.clients.paperclip, paperclipAgent.companyId, paperclipAgent.id, {
    adapterConfig: {
      headers: {
        "x-openclaw-token": token
      }
    }
  }, ctx.logger);

  const patchedAgent = await ctx.clients.paperclip.getAgent(paperclipAgent.id);

  return {
    ok: true,
    data: {
      paperclipAgent: patchedAgent,
      gatewayTokenSynced: true
    }
  };
}

